import java.util.*;
import java.util.stream.*;

public class Main {
    public static void main(String[] args) {
        List<String> names = Arrays.asList(
            "Alice", "Bob", "Andrew", "Charlie", "Anna", "Dave"
        );

        // Filter, uppercase, sort, print
        names.stream()
            .filter(n -> n.startsWith("A"))
            .map(String::toUpperCase)
            .sorted()
            .forEach(System.out::println);
        // prints: ALICE, ANDREW, ANNA

        long count = names.stream()
            .filter(n -> n.length() > 4)
            .count();
        System.out.println("Long names: " + count);  // 3
    }
}
